/**
 * Head-to-head bench: DC-only (paleta) vs jSquash full mozjpeg decode.
 *
 * Runs against real JPEG fixtures generated by PIL at varying resolutions
 * and subsamplings. The numbers we care about:
 *   - mean decode time per call
 *   - p99 decode time per call
 *   - output dimensions (DC-only is always 1/8 of jSquash)
 *
 * Why the difference is expected:
 *   jSquash does Huffman + dequantize + IDCT for 64 coefficients per block.
 *   DC-only does Huffman + dequantize for the DC coefficient only and skips
 *   IDCT entirely. Roughly 1/64 the compute per block, in theory.
 */

import { readFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { bench, describe } from "vitest";
import { decodeJpegDcOnly, initWasm } from "@paleta/core";

// Init paleta WASM at module top.
const PALETA_WASM = fileURLToPath(
  new URL("../packages/core/wasm/paleta_core_bg.wasm", import.meta.url),
);
await initWasm(await readFile(PALETA_WASM));

// Init jSquash mozjpeg WASM at module top.
const MOZJPEG_WASM = fileURLToPath(
  new URL(
    "../node_modules/.pnpm/@jsquash+jpeg@1.6.0/node_modules/@jsquash/jpeg/codec/dec/mozjpeg_dec.wasm",
    import.meta.url,
  ),
);
const jsquash = (await import("@jsquash/jpeg/decode")) as unknown as {
  default: (buffer: ArrayBuffer) => Promise<{ data: Uint8ClampedArray; width: number; height: number }>;
  init: (module: WebAssembly.Module) => Promise<void>;
};
const mozjpegBytes = await readFile(MOZJPEG_WASM);
// jSquash's `init` accepts a compiled Module or bytes.
await jsquash.init(await WebAssembly.compile(mozjpegBytes));

async function loadFixture(name: string): Promise<Uint8Array> {
  const path = fileURLToPath(
    new URL(`../test/fixtures/${name}`, import.meta.url),
  );
  return new Uint8Array(await readFile(path));
}

const small444 = await loadFixture("red-blue-444.jpg"); // 64×64
const small420 = await loadFixture("four-quadrants-420.jpg"); // 128×128
const scene420 = await loadFixture("paleta-scene-420.jpg"); // 640×480
const scene444 = await loadFixture("paleta-scene-444.jpg"); // 640×480
const large420 = await loadFixture("paleta-scene-large-420.jpg"); // 1280×720

describe("64×64 solid 4:4:4 — tiny baseline JPEG", () => {
  bench("paleta: DC-only", async () => {
    await decodeJpegDcOnly(small444);
  });
  bench("jSquash: full decode", async () => {
    await jsquash.default(small444);
  });
});

describe("128×128 four-quadrants 4:2:0", () => {
  bench("paleta: DC-only", async () => {
    await decodeJpegDcOnly(small420);
  });
  bench("jSquash: full decode", async () => {
    await jsquash.default(small420);
  });
});

describe("640×480 realistic scene 4:4:4", () => {
  bench("paleta: DC-only", async () => {
    await decodeJpegDcOnly(scene444);
  });
  bench("jSquash: full decode", async () => {
    await jsquash.default(scene444);
  });
});

describe("640×480 realistic scene 4:2:0", () => {
  bench("paleta: DC-only", async () => {
    await decodeJpegDcOnly(scene420);
  });
  bench("jSquash: full decode", async () => {
    await jsquash.default(scene420);
  });
});

describe("1280×720 realistic scene 4:2:0", () => {
  bench("paleta: DC-only", async () => {
    await decodeJpegDcOnly(large420);
  });
  bench("jSquash: full decode", async () => {
    await jsquash.default(large420);
  });
});

/** End-to-end palette extraction: the number users actually care about.
 *  DC-only decodes a tiny image that the histogram chews through quickly.
 *  Full decode yields a big buffer that needs resize before histogram. */
import { getPalette } from "@paleta/core";

const dcDecoder = async (bytes: Uint8Array) => {
  const dc = await decodeJpegDcOnly(bytes);
  if (!dc) throw new Error("dc-only returned undefined");
  return dc;
};
const jsquashDecoder = async (bytes: Uint8Array) => {
  const img = await jsquash.default(
    bytes.byteOffset === 0 && bytes.byteLength === bytes.buffer.byteLength
      ? (bytes.buffer as ArrayBuffer)
      : (bytes.slice().buffer as ArrayBuffer),
  );
  return {
    data: new Uint8Array(img.data.buffer, img.data.byteOffset, img.data.byteLength),
    width: img.width,
    height: img.height,
  };
};

describe("end-to-end getPalette: 640×480 4:2:0", () => {
  bench("DC-only path (useDcOnlyJpeg=true)", async () => {
    await getPalette(scene420, {
      decoder: jsquashDecoder,
      useDcOnlyJpeg: true,
      colorCount: 8,
    });
  });
  bench("full-decode path (jSquash + resize)", async () => {
    await getPalette(scene420, {
      decoder: jsquashDecoder,
      colorCount: 8,
    });
  });
});

describe("end-to-end getPalette: 1280×720 4:2:0", () => {
  bench("DC-only path (useDcOnlyJpeg=true)", async () => {
    await getPalette(large420, {
      decoder: jsquashDecoder,
      useDcOnlyJpeg: true,
      colorCount: 8,
    });
  });
  bench("full-decode path (jSquash + resize)", async () => {
    await getPalette(large420, {
      decoder: jsquashDecoder,
      colorCount: 8,
    });
  });
});

void dcDecoder;
